import React, { useState } from 'react';
import { FaSearch, FaFilter, FaTimes, FaCalendarAlt } from 'react-icons/fa';

function EmployeeSearch({ onSearch, departments, positions }) {
  const [searchParams, setSearchParams] = useState({
    search_term: '',
    department_id: '',
    position_id: '',
    status: '',
    hire_date_from: '',
    hire_date_to: '',
  });

  const [showAdvanced, setShowAdvanced] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setSearchParams(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSearch = (e) => {
    e.preventDefault();

    const filteredParams = {};

    if (searchParams.search_term.trim()) {
      filteredParams.search_term = searchParams.search_term.trim();
    }
    if (searchParams.department_id) {
      filteredParams.department_id = parseInt(searchParams.department_id);
    }
    if (searchParams.position_id) {
      filteredParams.position_id = parseInt(searchParams.position_id);
    }
    if (searchParams.status) {
      filteredParams.status = searchParams.status;
    }
    if (searchParams.hire_date_from) {
      filteredParams.hire_date_from = searchParams.hire_date_from;
    }
    if (searchParams.hire_date_to) {
      filteredParams.hire_date_to = searchParams.hire_date_to;
    }

    onSearch(filteredParams);
  };

  const handleReset = () => {
    const resetParams = {
      search_term: '',
      department_id: '',
      position_id: '',
      status: '',
      hire_date_from: '',
      hire_date_to: '',
    };
    setSearchParams(resetParams);
    onSearch({});
  };

  const removeFilter = (filterName) => {
    const newParams = {
      ...searchParams,
      [filterName]: '',
    };
    setSearchParams(newParams);

    const filteredParams = {};
    Object.entries(newParams).forEach(([key, value]) => {
      if (value && value !== '') {
        if (key === 'department_id' || key === 'position_id') {
          filteredParams[key] = parseInt(value);
        } else {
          filteredParams[key] = value;
        }
      }
    });
    onSearch(filteredParams);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleSearch(e);
    }
  };

  const hasActiveFilters = Object.values(searchParams).some(val => val !== '');

  const getDepartmentName = (id) => {
    const dept = departments.find(d => d.DepartmentID === parseInt(id));
    return dept ? dept.DepartmentName : id;
  };

  const getPositionName = (id) => {
    const pos = positions.find(p => p.PositionID === parseInt(id));
    return pos ? pos.PositionName : id;
  };

  return (
    <div className="employee-search">
      <form onSubmit={handleSearch}>
        <div className="search-container">
          <div className="search-input-wrapper">
            <FaSearch className="search-icon" />
            <input
              type="text"
              name="search_term"
              className="search-input"
              placeholder="Search by name, email, phone, or employee ID..."
              value={searchParams.search_term}
              onChange={handleChange}
              onKeyPress={handleKeyPress}
            />
            {searchParams.search_term && (
              <button
                type="button"
                className="search-clear-btn"
                onClick={() => removeFilter('search_term')}
              >
                <FaTimes />
              </button>
            )}
          </div>

          <button
            type="button"
            className={`btn ${showAdvanced ? 'btn-primary' : 'btn-secondary'}`}
            onClick={() => setShowAdvanced(!showAdvanced)}
          >
            <FaFilter />
            {showAdvanced ? 'Hide Filters' : 'Filters'}
          </button>

          <button type="submit" className="btn btn-primary">
            <FaSearch />
            Search
          </button>

          {hasActiveFilters && (
            <button type="button" className="btn btn-secondary" onClick={handleReset}>
              <FaTimes />
              Clear All
            </button>
          )}
        </div>

        {showAdvanced && (
          <div className="advanced-filters">
            <div className="advanced-filters-header">
              <h4>
                <FaFilter style={{ marginRight: '8px' }} />
                Advanced Filters
              </h4>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Department</label>
                <select
                  name="department_id"
                  className="form-control"
                  value={searchParams.department_id}
                  onChange={handleChange}
                >
                  <option value="">All Departments</option>
                  {departments.map((dept) => (
                    <option key={dept.DepartmentID} value={dept.DepartmentID}>
                      {dept.DepartmentName}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Position</label>
                <select
                  name="position_id"
                  className="form-control"
                  value={searchParams.position_id}
                  onChange={handleChange}
                >
                  <option value="">All Positions</option>
                  {positions.map((pos) => (
                    <option key={pos.PositionID} value={pos.PositionID}>
                      {pos.PositionName}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Status</label>
                <select
                  name="status"
                  className="form-control"
                  value={searchParams.status}
                  onChange={handleChange}
                >
                  <option value="">All Statuses</option>
                  <option value="Đang làm việc">Đang làm việc</option>
                  <option value="Nghỉ phép">Nghỉ phép</option>
                  <option value="Thử việc">Thử việc</option>
                  <option value="Thực tập">Thực tập</option>
                </select>
              </div>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label className="form-label">
                  <FaCalendarAlt style={{ marginRight: '6px' }} />
                  Hire Date From
                </label>
                <input
                  type="date"
                  name="hire_date_from"
                  className="form-control"
                  value={searchParams.hire_date_from}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group">
                <label className="form-label">
                  <FaCalendarAlt style={{ marginRight: '6px' }} />
                  Hire Date To
                </label>
                <input
                  type="date"
                  name="hire_date_to"
                  className="form-control"
                  value={searchParams.hire_date_to}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group"></div>
            </div>
          </div>
        )}

        {hasActiveFilters && (
          <div className="active-filters">
            <span className="active-filters-label">Active Filters:</span>
            <div className="filter-tags">
              {searchParams.search_term && (
                <span className="filter-tag">
                  <span className="filter-tag-label">Search:</span>
                  "{searchParams.search_term}"
                  <button type="button" onClick={() => removeFilter('search_term')}>
                    <FaTimes />
                  </button>
                </span>
              )}

              {searchParams.department_id && (
                <span className="filter-tag">
                  <span className="filter-tag-label">Department:</span>
                  {getDepartmentName(searchParams.department_id)}
                  <button type="button" onClick={() => removeFilter('department_id')}>
                    <FaTimes />
                  </button>
                </span>
              )}

              {searchParams.position_id && (
                <span className="filter-tag">
                  <span className="filter-tag-label">Position:</span>
                  {getPositionName(searchParams.position_id)}
                  <button type="button" onClick={() => removeFilter('position_id')}>
                    <FaTimes />
                  </button>
                </span>
              )}

              {searchParams.status && (
                <span className="filter-tag">
                  <span className="filter-tag-label">Status:</span>
                  {searchParams.status}
                  <button type="button" onClick={() => removeFilter('status')}>
                    <FaTimes />
                  </button>
                </span>
              )}

              {searchParams.hire_date_from && (
                <span className="filter-tag">
                  <span className="filter-tag-label">From:</span>
                  {searchParams.hire_date_from}
                  <button type="button" onClick={() => removeFilter('hire_date_from')}>
                    <FaTimes />
                  </button>
                </span>
              )}

              {searchParams.hire_date_to && (
                <span className="filter-tag">
                  <span className="filter-tag-label">To:</span>
                  {searchParams.hire_date_to}
                  <button type="button" onClick={() => removeFilter('hire_date_to')}>
                    <FaTimes />
                  </button>
                </span>
              )}
            </div>
          </div>
        )}
      </form>
    </div>
  );
}

export default EmployeeSearch;
